import{_ as e,o as t,c as a,Q as i}from"./chunks/framework.b67c47e6.js";const m=JSON.parse('{"title":"Production Planning","description":"","frontmatter":{},"headers":[],"relativePath":"guide/planning/index.md","filePath":"guide/planning/index.md","lastUpdated":1773939149000}'),r={name:"guide/planning/index.md"},o=i('<h1 id="production-planning" tabindex="-1">Production Planning <a class="header-anchor" href="#production-planning" aria-label="Permalink to &quot;Production Planning&quot;">​</a></h1><p>The Production Planning view lets you schedule constructibles (assemblies and modules) on a calendar, manage production priorities, and visualize workload across your production lines.</p><nav class="table-of-contents"><ul><li><a href="#calendar-view">Calendar View</a><ul><li><a href="#visual-indicators">Visual Indicators</a></li></ul></li><li><a href="#scheduling-constructibles">Scheduling Constructibles</a><ul><li><a href="#drag-and-drop">Drag and Drop</a></li><li><a href="#priority">Priority</a></li><li><a href="#multi-select">Multi-Select</a></li></ul></li><li><a href="#filters">Filters</a></li><li><a href="#settings">Settings</a></li><li><a href="#workload">Workload</a></li><li><a href="#saving-changes">Saving Changes</a></li></ul></nav><h2 id="calendar-view" tabindex="-1">Calendar View <a class="header-anchor" href="#calendar-view" aria-label="Permalink to &quot;Calendar View&quot;">​</a></h2><p>The calendar displays 1 to 4 months at a time, with each day showing the constructibles scheduled for production on that date. Items are ordered by priority within each day.</p><h3 id="visual-indicators" tabindex="-1">Visual Indicators <a class="header-anchor" href="#visual-indicators" aria-label="Permalink to &quot;Visual Indicators&quot;">​</a></h3><ul><li><strong>Green</strong> — Selected constructible.</li><li><strong>Orange</strong> — Modified (unsaved changes).</li><li><strong>Red</strong> — Overdue (past scheduled date, not yet produced).</li><li><strong>Grey</strong> — Past dates.</li><li><strong>Blue</strong> — Normal scheduled item.</li></ul><h2 id="scheduling-constructibles" tabindex="-1">Scheduling Constructibles <a class="header-anchor" href="#scheduling-constructibles" aria-label="Permalink to &quot;Scheduling Constructibles&quot;">​</a></h2><h3 id="drag-and-drop" tabindex="-1">Drag and Drop <a class="header-anchor" href="#drag-and-drop" aria-label="Permalink to &quot;Drag and Drop&quot;">​</a></h3><p>Drag a constructible from one date to another to reschedule it. You can also drag items from the <strong>Unscheduled Constructibles</strong> panel into the calendar.</p><h3 id="priority" tabindex="-1">Priority <a class="header-anchor" href="#priority" aria-label="Permalink to &quot;Priority&quot;">​</a></h3><p>Within a single day, constructibles are produced in priority order (1 = first). Use the up/down arrows to reorder items within a date.</p><h3 id="multi-select" tabindex="-1">Multi-Select <a class="header-anchor" href="#multi-select" aria-label="Permalink to &quot;Multi-Select&quot;">​</a></h3><ul><li><strong>Ctrl+Click</strong> — Select multiple individual items.</li><li><strong>Shift+Click</strong> — Select a range of items.</li></ul><p>This allows you to move or modify several constructibles at once.</p><h2 id="filters" tabindex="-1">Filters <a class="header-anchor" href="#filters" aria-label="Permalink to &quot;Filters&quot;">​</a></h2><ul><li><strong>Production line</strong> — Show only constructibles assigned to a specific line.</li><li><strong>Projects</strong> — Filter by one or more projects.</li></ul><h2 id="settings" tabindex="-1">Settings <a class="header-anchor" href="#settings" aria-label="Permalink to &quot;Settings&quot;">​</a></h2><p>Click the settings icon to configure the calendar display:</p><table><thead><tr><th>Setting</th><th>Description</th></tr></thead><tbody><tr><td><strong>Displayed months</strong></td><td>Show 1 to 4 months at a time.</td></tr><tr><td><strong>Calendar height</strong></td><td>Adjust the row height.</td></tr><tr><td><strong>Shown weekdays</strong></td><td>Choose which days of the week to display.</td></tr><tr><td><strong>Visible fields</strong></td><td>Select which data to show on each card (design name, UUID, client order, project, super-project, status).</td></tr><tr><td><strong>Workload display</strong></td><td>Toggle workload heatmap on calendar dates.</td></tr><tr><td><strong>Show ready items</strong></td><td>Show or hide already-completed constructibles.</td></tr></tbody></table><h2 id="workload" tabindex="-1">Workload <a class="header-anchor" href="#workload" aria-label="Permalink to &quot;Workload&quot;">​</a></h2><p>When enabled, each calendar date shows a workload indicator based on the total expected production time for that day compared to the production line&#39;s capacity.</p><p>The workload is calculated from:</p><ul><li>Design area (m²) of each scheduled constructible</li><li>Expected work time per m² at each station</li><li>Production line&#39;s configured daily capacity (minutes per day)</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>You can override the daily work capacity in the planning settings to model different scenarios (e.g., overtime, reduced shifts).</p></div><h2 id="saving-changes" tabindex="-1">Saving Changes <a class="header-anchor" href="#saving-changes" aria-label="Permalink to &quot;Saving Changes&quot;">​</a></h2><p>After making scheduling changes, click <strong>Save</strong> to persist the updated dates and priorities. Unsaved changes are highlighted in orange.</p>',27),n=[o];function l(s,d,c,h,u,g){return t(),a("div",null,n)}const f=e(r,[["render",l]]);export{m as __pageData,f as default};
